import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Chamber } from '../../core/models';

@Component({
  selector: 'app-legislator-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './legislator-form.component.html',
  styleUrl: './legislator-form.component.css',
})
export class LegislatorFormComponent implements OnInit {
  private fb = inject(FormBuilder);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly chambers: Chamber[] = ['house', 'senate'];

  legislatorId = signal<string | null>(null);
  saving = signal(false);
  readonly isEdit = computed(() => !!this.legislatorId());

  form = this.fb.group({
    name: ['', [Validators.required]],
    chamber: ['house' as Chamber, [Validators.required]],
    district: ['', [Validators.required]],
    party: ['', [Validators.required]],
  });

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    this.legislatorId.set(id);
    if (id) {
      // Mock prefill — service_agent replaces with getLegislator(id).
      this.form.patchValue({
        name: 'Sen. Marcia Holloway',
        chamber: 'senate',
        district: 'S-12',
        party: 'Republican',
      });
    }
  }

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.saving.set(true);
    const id = this.legislatorId();
    setTimeout(() => {
      this.saving.set(false);
      this.router.navigate(id ? ['/legislators', id] : ['/legislators']);
    }, 250);
  }

  cancel(): void {
    const id = this.legislatorId();
    this.router.navigate(id ? ['/legislators', id] : ['/legislators']);
  }
}
